  1→import { useMemo, useRef } from 'react';
  2→import { TOOLS } from './tools';
  3→import { createWallDrawHandler } from './handlers/wallDrawHandler';
  4→import { createSelectHandler } from './handlers/selectHandler';
  5→import { createDimensionPlaceHandler } from './handlers/dimensionPlaceHandler';
  6→import { createDoorPlaceHandler } from './handlers/doorPlaceHandler';
  7→import { createWindowPlaceHandler } from './handlers/windowPlaceHandler';
  8→import { createColumnPlaceHandler } from './handlers/columnPlaceHandler';
  9→import { createRoomPlaceHandler } from './handlers/roomPlaceHandler';
 10→import { createBeamPlaceHandler } from './handlers/beamPlaceHandler';
 11→import { createSlabPlaceHandler } from './handlers/slabPlaceHandler';
 12→import { createStairPlaceHandler } from './handlers/stairPlaceHandler';
 13→import { createSectionPlaceHandler } from './handlers/sectionPlaceHandler';
 14→import { createLandingPlaceHandler } from './handlers/landingPlaceHandler';
 15→import { createFixturePlaceHandler } from './handlers/fixturePlaceHandler';
 16→import { createRailingPlaceHandler } from './handlers/railingPlaceHandler';
 17→import { createElevationSelectHandler } from './handlers/elevationSelectHandler';
 18→import { createRoofSelectHandler } from './handlers/roofSelectHandler';
 19→import { createRoofParapetPlaceHandler } from './handlers/roofParapetPlaceHandler';
 20→import { createRoofDrainPlaceHandler } from './handlers/roofDrainPlaceHandler';
 21→import { createRoofOpeningPlaceHandler } from './handlers/roofOpeningPlaceHandler';
 22→import { createTrussSelectHandler } from './handlers/trussSelectHandler';
 23→import { createTrussDrawHandler } from './handlers/trussDrawHandler';
 24→
 25→function createReadOnlyHandler() {
 26→  return {
 27→    onMouseDown() {},
 28→    onMouseMove() {},
 29→    onMouseUp() {},
 30→    onDoubleClick() {},
 31→    onKeyDown() {},
 32→    getCursor() {
 33→      return 'default';
 34→    },
 35→  };
 36→}
 37→
 38→export function useEditorTool({ activeTool, dispatch, editorDispatch, project, getFloor, activeFloorId, roofSystem, trussSystems, modelTarget, viewport, snapEnabled, selectedId, selectedType, toolState, viewMode, activePhaseId }) {
 39→  const getFloorRef = useRef(getFloor);
 40→  getFloorRef.current = getFloor;
 41→
 42→  const handler = useMemo(() => {
 43→    if (modelTarget === 'truss') {
 44→      if (viewMode !== 'plan') {
 45→        return createReadOnlyHandler();
 46→      }
 47→
 48→      const trussCtx = {
 49→        dispatch,
 50→        editorDispatch,
 51→        getFloor: (...args) => getFloorRef.current(...args),
 52→        activeFloorId,
 53→        trussSystems,
 54→        viewport,
 55→        selectedId,
 56→        selectedType,
 57→        viewMode,
 58→      };
 59→
 60→      switch (activeTool) {
 61→        case TOOLS.TRUSS_DRAW:
 62→          return createTrussDrawHandler(trussCtx);
 63→        case TOOLS.SELECT:
 64→        default:
 65→          return createTrussSelectHandler(trussCtx);
 66→      }
 67→    }
 68→
 69→    if (modelTarget === 'roof') {
 70→      if (viewMode !== 'plan') {
 71→        return createReadOnlyHandler();
 72→      }
 73→
 74→      const roofCtx = {
 75→        dispatch,
 76→        editorDispatch,
 77→        roofSystem,
 78→        viewport,
 79→      };
 80→
 81→      switch (activeTool) {
 82→        case TOOLS.ROOF_PARAPET:
 83→          return createRoofParapetPlaceHandler(roofCtx);
 84→        case TOOLS.ROOF_DRAIN:
 85→          return createRoofDrainPlaceHandler(roofCtx);
 86→        case TOOLS.ROOF_OPENING:
 87→          return createRoofOpeningPlaceHandler(roofCtx);
 88→        case TOOLS.SELECT:
 89→        default:
 90→          return createRoofSelectHandler(roofCtx);
 91→      }
 92→    }
 93→
 94→    if (viewMode?.startsWith('elevation_')) {
 95→      return createElevationSelectHandler({
 96→        dispatch,
 97→        editorDispatch,
 98→        project,
 99→        getFloor: (...args) => getFloorRef.current(...args),
100→        activeFloorId,
101→        viewport,
102→        snapEnabled,
103→        viewMode,
104→      });
105→    }
106→
107→    if (viewMode !== 'plan') {
108→      return createReadOnlyHandler();
109→    }
110→
111→    const ctx = {
112→      dispatch, editorDispatch,
113→      getFloor: (...args) => getFloorRef.current(...args),
114→      activeFloorId, viewport, snapEnabled, activePhaseId,
115→    };
116→
117→    switch (activeTool) {
118→      case TOOLS.DIMENSION:
119→        return createDimensionPlaceHandler(ctx);
120→      case TOOLS.WALL:
121→        return createWallDrawHandler(ctx);
122→      case TOOLS.BEAM:
123→        return createBeamPlaceHandler(ctx);
124→      case TOOLS.STAIR:
125→        return createStairPlaceHandler(ctx);
126→      case TOOLS.SECTION:
127→        return createSectionPlaceHandler(ctx);
128→      case TOOLS.SLAB:
129→        return createSlabPlaceHandler(ctx);
130→      case TOOLS.ROOM:
131→        return createRoomPlaceHandler(ctx);
132→      case TOOLS.SELECT:
133→        return createSelectHandler(ctx);
134→      case TOOLS.DOOR:
135→        return createDoorPlaceHandler(ctx);
136→      case TOOLS.WINDOW:
137→        return createWindowPlaceHandler(ctx);
138→      case TOOLS.COLUMN:
139→        return createColumnPlaceHandler(ctx);
140→      case TOOLS.LANDING:
141→        return createLandingPlaceHandler(ctx);
142→      case TOOLS.FIXTURE:
143→        return createFixturePlaceHandler(ctx);
144→      case TOOLS.RAILING:
145→        return createRailingPlaceHandler(ctx);
146→      default:
147→        return null;
148→    }
149→  }, [activeTool, activeFloorId, project, roofSystem, trussSystems, modelTarget, viewport.zoom, snapEnabled, viewMode, activePhaseId, selectedId, selectedType]);
150→
151→  return {
152→    onMouseDown: (modelPos, e) => handler?.onMouseDown?.(modelPos, e, toolState),
153→    onMouseMove: (modelPos, e) => handler?.onMouseMove?.(modelPos, e, toolState, selectedId, selectedType),
154→    onMouseUp: (modelPos, e) => handler?.onMouseUp?.(modelPos, e, toolState),
155→    onDoubleClick: (modelPos, e) => handler?.onDoubleClick?.(modelPos, e, toolState),
156→    onKeyDown: (e) => handler?.onKeyDown?.(e, toolState, selectedId, selectedType),
157→    getCursor: () => handler?.getCursor?.(toolState) || 'default',
158→  };
159→}
