 52→  onSave,
 53→  onLoad,
 54→  isSidebarCollapsed,
 55→  isPropertiesCollapsed,
 56→  onToggleSidebar,
 57→  onToggleProperties,
 58→}) {
 59→  const {
 60→    activeTool,
 61→    showGrid,
 62→    snapEnabled,
 63→    activeFloorId,
 64→    viewMode,
 65→    workspaceMode,
 66→    modelTarget,
 67→    toolState,
 68→    activePhaseId,
 69→    selectedId,
 70→    selectedType,
