154→    dispatch({ type: 'REDO' });
155→    editorDispatch({ type: 'DESELECT' });
156→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Redid last change.' });
157→  }, [canRedo, dispatch, editorDispatch]);
158→
159→  const handleDetectRooms = () => {
160→    const floor = project.floors.find(f => f.id === activeFloorId);
161→    if (!floor || floor.walls.length < 3) {
162→      editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Draw at least 3 walls first.' });
163→      return;
164→    }
165→    const detected = detectRooms(floor.walls, floor.columns || []);
166→    const rooms = detected.map((d, i) => {
167→      const room = createRoom(`Room ${i + 1}`, d.points);
168→      room.phaseId = activePhaseId || null;
169→      return room;
170→    });
171→    dispatch({ type: 'ROOMS_SET', floorId: activeFloorId, rooms });
172→    editorDispatch({ type: 'DESELECT' });
173→    editorDispatch({
174→      type: 'SET_STATUS_MESSAGE',
175→      message: rooms.length ? `Detected ${rooms.length} room${rooms.length === 1 ? '' : 's'}.` : 'No enclosed rooms detected.',
176→    });
177→  };
178→
