182→      if (isTypingTarget(e.target)) return;
183→
184→      const key = e.key.toLowerCase();
185→      const isRedo = (key === 'z' && e.shiftKey) || key === 'y';
186→      const isUndo = key === 'z' && !e.shiftKey;
187→      if (!isUndo && !isRedo) return;
188→
189→      e.preventDefault();
190→      if (isRedo) {
