248→        </Tooltip>
249→        <Tooltip label="Copy" shortcut="Ctrl+C">
250→          <button
251→            className={styles.btn}
252→            onClick={copySelection}
253→            disabled={!canCopySelection || modelTarget !== 'floor' || workspaceMode !== 'model'}
254→            aria-label="Copy"
