274→            aria-label="Paste"
275→          >
276→            <PasteIcon className={styles.icon} />
277→          </button>
278→        </Tooltip>
279→      </div>
280→
281→      <div className={styles.segmentedGroup}>
282→        <button
283→          className={workspaceMode === 'model' && modelTarget === 'floor' ? styles.segmentedBtnActive : styles.segmentedBtn}
284→          onClick={() => {
