 5→function snapToGrid(value) {
 6→  return Math.round(value / GRID_MINOR) * GRID_MINOR;
 7→}
 8→
 9→export function createFixturePlaceHandler({ dispatch, editorDispatch, getFloor, activeFloorId, snapEnabled, activePhaseId }) {
10→  return {
11→    onMouseMove(modelPos) {
12→      let x = modelPos.x;
13→      let y = modelPos.y;
14→      if (snapEnabled) {
15→        x = snapToGrid(x);
16→        y = snapToGrid(y);
17→      }
18→      editorDispatch({
19→        type: 'UPDATE_TOOL_STATE',
20→        payload: { previewX: x, previewY: y },
21→      });
22→    },
23→
24→    onMouseDown(modelPos, e, toolState) {
25→      if (e.button !== 0) return;
26→      let x = modelPos.x;
27→      let y = modelPos.y;
28→      if (snapEnabled) {
29→        x = snapToGrid(x);
30→        y = snapToGrid(y);
31→      }
32→      const fixtureType = toolState?.fixtureType || FIXTURE_TYPES.KITCHEN_TOP;
33→      const rotation = toolState?.previewRotation || 0;
34→      const fixture = createFixture(fixtureType, x, y, { rotation });
35→      fixture.phaseId = activePhaseId || null;
36→      dispatch({ type: 'FIXTURE_ADD', floorId: activeFloorId, fixture });
37→    },
38→
39→    onKeyDown(e, toolState) {
40→      if (e.key.toLowerCase() === 'r' && !e.ctrlKey && !e.metaKey) {
41→        e.preventDefault();
42→        const current = toolState?.previewRotation || 0;
43→        const next = (current + 90) % 360;
44→        editorDispatch({
45→          type: 'UPDATE_TOOL_STATE',
46→          payload: { previewRotation: next },
47→        });
48→      } else if (e.key === 'Escape') {
49→        editorDispatch({ type: 'SET_TOOL', tool: 'select' });
50→      }
51→    },
52→
53→    getCursor() {
54→      return 'crosshair';
55→    },
56→  };
57→}
